const input = $input.first().json;
const body = input.body || input;
const types = body.types || ['sentiment', 'tags', 'moderation'];
const reviewText = body.reviewText || {};
const store = body.storeContext || {};
const storeName = store.storeName || 'Ecommerce Store';
const storeEmail = store.storeEmail || '';
const storeAddress = store.storeAddress || '';
const customerName = reviewText.customerName || 'Customer';
const firstName = (customerName.trim().split(/\s+/)[0] || customerName);

function buildReplySystemPrompt() {
  return `You are a professional ecommerce customer support manager for ${storeName}.\nWrite an empathetic, professional reply (80-120 words) to a product review.\n\nRequirements:\n- Greet the customer by their first name ("${firstName}").\n- Never use placeholders such as "[Store Name]", "Dear valued customer", or similar generic openings.\n- End with a professional sign-off using exactly this store name: ${storeName}\n- After the sign-off, include contact details on separate lines: ${storeEmail} and ${storeAddress}\n- Do not promise refunds unless the review explicitly requests one.\n- Return only the reply text, no JSON or markdown fences.`;
}

function buildReplyUserPrompt() {
  return `Customer name: ${customerName} (use first name "${firstName}" in greeting)\nRating: ${reviewText.rating}/5\nTitle: ${reviewText.title}\nReview: ${reviewText.content}\n\nStore name: ${storeName}\nStore email: ${storeEmail}\nStore address: ${storeAddress}`;
}
const text = `${reviewText.title || ''}\n\n${reviewText.content || ''}`.trim();
const providerOrder = ($vars.AI_FALLBACK_PROVIDER_ORDER || 'groq,openrouter,openai').split(',').map((s) => s.trim());
const models = {
  groq: $vars.GROQ_MODEL || 'llama-3.3-70b-versatile',
  openrouter: $vars.OPENROUTER_MODEL || 'google/gemini-2.5-flash',
  openai: $vars.OPENAI_MODEL || 'gpt-4o-mini'
};
const keys = {
  groq: $vars.GROQ_API_KEY,
  openrouter: $vars.OPENROUTER_API_KEY,
  openai: $vars.OPENAI_API_KEY
};

async function chat(provider, system, user) {
  if (provider === 'groq') {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.groq.com/openai/v1/chat/completions',
      headers: { Authorization: `Bearer ${keys.groq}`, 'Content-Type': 'application/json' },
      body: { model: models.groq, temperature: 0.3, messages: [{ role: 'system', content: system }, { role: 'user', content: user }] },
      json: true
    });
    return res.choices?.[0]?.message?.content || '';
  }
  if (provider === 'openrouter') {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://openrouter.ai/api/v1/chat/completions',
      headers: { Authorization: `Bearer ${keys.openrouter}`, 'Content-Type': 'application/json' },
      body: { model: models.openrouter, temperature: 0.3, messages: [{ role: 'system', content: system }, { role: 'user', content: user }] },
      json: true
    });
    return res.choices?.[0]?.message?.content || '';
  }
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: { Authorization: `Bearer ${keys.openai}`, 'Content-Type': 'application/json' },
    body: { model: models.openai, temperature: 0.3, messages: [{ role: 'system', content: system }, { role: 'user', content: user }] },
    json: true
  });
  return res.choices?.[0]?.message?.content || '';
}

const prompts = {
  sentiment: 'Reply JSON only: {"sentiment":"positive|neutral|negative","confidence":0.95}',
  tags: 'Return JSON array of 2-5 short tags, e.g. ["Good Quality","Fast Delivery"]',
  moderation: 'Reply JSON only: {"flagged":true|false,"reason":"..."}',
  summary: 'Write a balanced 2-3 sentence product review summary for shoppers.'
};

const results = [];
const startAll = Date.now();

for (const type of types) {
  if (type === 'full_analysis') continue;
  let lastError = null;
  let saved = false;
  for (const provider of providerOrder) {
    if (!keys[provider]) continue;
    const t0 = Date.now();
    try {
      let system = prompts[type] || prompts.sentiment;
      let user = text;
      if (type === 'reply') {
        system = buildReplySystemPrompt();
        user = buildReplyUserPrompt();
      }
      const raw = await chat.call(this, provider, system, user);
      let content;
      if (type === 'sentiment') {
        const parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || '{}');
        content = JSON.stringify(parsed);
      } else if (type === 'tags') {
        const parsed = JSON.parse(raw.match(/\[[\s\S]*\]/)?.[0] || '[]');
        content = JSON.stringify({ tags: parsed });
      } else if (type === 'moderation') {
        const parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || '{"flagged":false}');
        content = JSON.stringify(parsed);
      } else if (type === 'reply') {
        content = JSON.stringify({ reply: raw.trim() });
      } else if (type === 'summary') {
        content = JSON.stringify({ summary: raw.trim() });
      } else {
        content = JSON.stringify({ raw });
      }
      await this.helpers.httpRequest({
        method: 'POST',
        url: `${$vars.CONVEX_SITE_URL}/n8n/review-ai/save-generation`,
        headers: { 'X-N8N-Secret': $vars.N8N_WEBHOOK_SECRET, 'Content-Type': 'application/json' },
        body: {
          reviewId: body.reviewId,
          productId: body.productId,
          type,
          content,
          provider,
          model: models[provider],
          source: body.source || 'fallback',
          triggeredBy: body.triggeredBy || 'n8n',
          jobId: body.jobId,
          durationMs: Date.now() - t0,
          mode: body.regenerationMode || 'version',
          title: reviewText.title
        },
        json: true
      });
      results.push({ type, provider, ok: true });
      saved = true;
      break;
    } catch (e) {
      lastError = e.message;
      await this.helpers.httpRequest({
        method: 'POST',
        url: `${$vars.CONVEX_SITE_URL}/n8n/review-ai/report-failure`,
        headers: { 'X-N8N-Secret': $vars.N8N_WEBHOOK_SECRET, 'Content-Type': 'application/json' },
        body: {
          reviewId: body.reviewId,
          type,
          provider,
          model: models[provider],
          source: body.source || 'fallback',
          error: lastError,
          durationMs: Date.now() - t0
        },
        json: true
      }).catch(() => {});
    }
  }
  if (!saved) {
    results.push({ type, ok: false, error: lastError });
  }
}

if (types.includes('full_analysis')) {
  const merged = {};
  for (const r of results) {
    if (!r.ok) continue;
  }
  const sentimentRes = results.find((r) => r.type === 'sentiment' && r.ok);
  const tagsRes = results.find((r) => r.type === 'tags' && r.ok);
  const modRes = results.find((r) => r.type === 'moderation' && r.ok);
}

return [{ json: { ok: true, results, durationMs: Date.now() - startAll, reviewId: body.reviewId } }];
